1	//! 全量索引引擎
2	//!
3	//! 遍历项目目录，用 rayon 并行解析所有源文件，
4	//! 提取符号、调用和导入信息，批量写入 tantivy 和 sled。
5	//!
6	//! 流程：
7	//! 1. `ignore` crate 遍历目录（自动 .gitignore 过滤）
8	//! 2. 按文件扩展名匹配解析器
9	//! 3. `rayon` 并行解析
10	//! 4. `crossbeam` channel 收集结果
11	//! 5. 批量写入 tantivy + sled
12	
13	use std::collections::HashMap;
14	use std::path::{Path, PathBuf};
15	use std::sync::Arc;
16	use std::time::SystemTime;
17	
18	use crossbeam::channel;
19	use rayon::prelude::*;
20	
21	use codeconnect_core::error::CodeConnectError;
22	use codeconnect_core::types::{FileMeta, SymbolKind};
23	use codeconnect_parser::factory::ParserRegistry;
24	use ignore::WalkBuilder;
25	
26	use crate::sled_store::SledStore;
27	use crate::tantivy_index::{TantivyIndex, CURRENT_SCHEMA_VERSION};
28	
29	// ============================================================================
30	// 统计结构
31	// ============================================================================
32	
33	/// 索引统计信息
34	///
35	/// 记录一次全量索引运行的整体结果，包括扫描文件数、
36	/// 解析成功率、提取的符号/调用/导入数量等。
37	#[derive(Debug, Clone)]
38	pub struct IndexStats {
39	    /// 扫描的文件总数
40	    pub files_scanned: u64,
41	    /// 成功解析的文件数
42	    pub files_parsed: u64,
43	    /// 提取的符号总数
44	    pub symbols_found: u64,
45	    /// 发现的调用点数
46	    pub calls_found: u64,
47	    /// 发现的导入数
48	    pub imports_found: u64,
49	    /// 解析失败的文件列表（路径 + 错误信息）
50	    pub failed_files: Vec<String>,
51	}
52	
53	/// 单个文件的索引统计（内部用）
54	#[derive(Debug, Clone, Default)]
55	struct FileIndexStats {
56	    symbols: u64,
57	    calls: u64,
58	    imports: u64,
59	}
60	
61	impl FileIndexStats {
62	    /// 合并多个文件的统计数据（供增量索引等后续阶段使用）
63	    #[allow(dead_code)]
64	    fn merge(stats: &[Self]) -> Self {
65	        let mut merged = Self::default();
66	        for s in stats {
67	            merged.symbols += s.symbols;
68	            merged.calls += s.calls;
69	            merged.imports += s.imports;
70	        }
71	        merged
72	    }
73	}
74	
75	// ============================================================================
76	// 解析结果 — channel 传输的数据包
77	// ============================================================================
78	
79	/// 单个文件的解析结果
80	///
81	/// 注意：`calls` 和 `imports` 字段目前仅作统计计数，
82	/// 其存储实现在后续的增量索引和引用解析阶段完成。
83	#[allow(dead_code)]
84	struct ParsedFile {
85	    /// 文件相对路径字符串
86	    relative_path: String,
87	    /// 内容 blake3 哈希的十六进制字符串
88	    content_hash: String,
89	    /// 编程语言名称
90	    language: &'static str,
91	    /// 提取的符号列表
92	    symbols: Vec<codeconnect_core::types::Symbol>,
93	    /// 提取的调用点列表
94	    calls: Vec<codeconnect_core::types::CallSite>,
95	    /// 提取的导入列表
96	    imports: Vec<codeconnect_core::types::Import>,
97	    /// 统计计数
98	    stats: FileIndexStats,
99	}
100	
101	/// 解析失败的文件信息
102	struct ParseFailure {
103	    /// 文件路径
104	    file_path: PathBuf,
105	    /// 错误信息
106	    error: String,
107	}
108	
109	// ============================================================================
110	// 全量索引引擎
111	// ============================================================================
112	
113	/// 全量索引引擎
114	///
115	/// 负责遍历项目目录中的所有源文件，并行解析并提取符号信息，
116	/// 然后将结果批量写入 tantivy 全文索引和 sled 键值存储。
117	///
118	/// # 使用示例
119	///
120	/// ```ignore
121	/// let mut registry = Arc::new(ParserRegistry::new());
122	/// // ... 注册解析器 ...
123	/// let tantivy = TantivyIndex::open_or_create(index_dir)?;
124	/// let sled = SledStore::open(sled_dir)?;
125	/// let indexer = FullIndexer::new(project_root, tantivy, sled, registry);
126	/// let stats = indexer.run()?;
127	/// println!("索引完成: {:?}", stats);
128	/// ```
129	pub struct FullIndexer {
130	    /// 项目根目录
131	    project_root: PathBuf,
132	    /// tantivy 全文搜索索引
133	    tantivy: TantivyIndex,
134	    /// sled 键值存储
135	    sled: SledStore,
136	    /// 解析器注册表
137	    parser_registry: Arc<ParserRegistry>,
138	}
139	
140	impl FullIndexer {
141	    /// 创建全量索引器
142	    ///
143	    /// # 参数
144	    /// - `project_root` — 项目根目录路径
145	    /// - `tantivy` — 已初始化的 tantivy 索引实例
146	    /// - `sled` — 已打开的 sled 存储实例
147	    /// - `parser_registry` — 已注册所有语言解析器的注册表
148	    pub fn new(
149	        project_root: &Path,
150	        tantivy: TantivyIndex,
151	        sled: SledStore,
152	        parser_registry: Arc<ParserRegistry>,
153	    ) -> Self {
154	        Self {
155	            project_root: project_root.to_path_buf(),
156	            tantivy,
157	            sled,
158	            parser_registry,
159	        }
160	    }
161	
162	    /// 运行全量索引
163	    ///
164	    /// 这是索引引擎的主入口，执行完整的索引流程：
165	    /// 文件收集 → 并行解析 → 批量写入 → 提交刷盘
166	    ///
167	    /// # 返回
168	    /// 返回 [`IndexStats`] 包含详细的统计信息。
169	    pub fn run(&mut self) -> Result<IndexStats, CodeConnectError> {
170	        // ====================================================================
171	        // 第一步：收集需要解析的文件列表
172	        // ====================================================================
173	        let files = self.collect_files()?;
174	        let files_scanned = files.len() as u64;
175	
176	        tracing::info!("扫描完成，共发现 {} 个源文件", files_scanned);
177	
178	        if files.is_empty() {
179	            return Ok(IndexStats {
180	                files_scanned: 0,
181	                files_parsed: 0,
182	                symbols_found: 0,
183	                calls_found: 0,
184	                imports_found: 0,
185	                failed_files: Vec::new(),
186	            });
187	        }
188	
189	        // ====================================================================
190	        // 第二步：使用 rayon 并行解析所有文件
191	        // 通过 crossbeam channel 收集解析结果和失败信息
192	        // ====================================================================
193	        let (success_tx, success_rx) = channel::unbounded::<ParsedFile>();
194	        let (failure_tx, failure_rx) = channel::unbounded::<ParseFailure>();
195	
196	        let project_root = Arc::new(self.project_root.clone());
197	        let parser_registry = Arc::clone(&self.parser_registry);
198	
199	        files.par_iter().for_each(|file_path| {
200	            match parse_single_file(file_path, &parser_registry, &project_root) {
201	                Ok(parsed) => {
202	                    let _ = success_tx.send(parsed);
203	                }
204	                Err(error) => {
205	                    let _ = failure_tx.send(ParseFailure {
206	                        file_path: file_path.clone(),
207	                        error,
208	                    });
209	                }
210	            }
211	        });
212	
213	        // 关闭发送端，以便接收端的迭代可以自然结束
214	        drop(success_tx);
215	        drop(failure_tx);
216	
217	        // ====================================================================
218	        // 第三步：收集结果并批量写入存储
219	        // ====================================================================
220	        let mut files_parsed: u64 = 0;
221	        let mut symbols_found: u64 = 0;
222	        let mut calls_found: u64 = 0;
223	        let mut imports_found: u64 = 0;
224	        let mut failed_files: Vec<String> = Vec::new();
225	
226	        // 按文件收集符号 ID 列表，用于写文件→符号映射
227	        let mut file_symbol_map: HashMap<String, FileIndexStats> = HashMap::new();
228	
229	        for parsed in success_rx {
230	            let relative_path = parsed.relative_path.clone();
231	            // 先统计再写入，避免 parsed 部分移动后无法借用
232	            let symbols_count = parsed.stats.symbols;
233	            let calls_count = parsed.stats.calls;
234	            let imports_count = parsed.stats.imports;
235	
236	            // 写入 sled 和 tantivy
237	            self.write_parsed_file(&parsed)?;
238	
239	            files_parsed += 1;
240	            symbols_found += symbols_count;
241	            calls_found += calls_count;
242	            imports_found += imports_count;
243	
244	            file_symbol_map.insert(relative_path, parsed.stats);
245	        }
246	
247	        // 收集解析失败的文件
248	        for failure in failure_rx {
249	            failed_files.push(format!(
250	                "{}: {}",
251	                failure.file_path.display(),
252	                failure.error
253	            ));
254	        }
255	
256	        // ====================================================================
257	        // 第四步：提交 tantivy 写入
258	        // ====================================================================
259	        self.tantivy.commit()?;
260	
261	        // ====================================================================
262	        // 第五步：写入 Schema 版本并刷盘
263	        // ====================================================================
264	        self.sled.put_schema_version(CURRENT_SCHEMA_VERSION)?;
265	        self.sled.flush()?;
266	
267	        tracing::info!(
268	            "全量索引完成: {} 成功 / {} 失败, {} 符号, {} 调用, {} 导入",
269	            files_parsed,
270	            failed_files.len(),
271	            symbols_found,
272	            calls_found,
273	            imports_found
274	        );
275	
276	        Ok(IndexStats {
277	            files_scanned,
278	            files_parsed,
279	            symbols_found,
280	            calls_found,
281	            imports_found,
282	            failed_files,
283	        })
284	    }
285	
286	    /// 收集项目目录下的所有源文件
287	    ///
288	    /// 使用 `ignore::WalkBuilder` 遍历目录树，自动应用
289	    /// `.gitignore` 规则过滤，仅收集支持的编程语言源文件。
290	    fn collect_files(&self) -> Result<Vec<PathBuf>, CodeConnectError> {
291	        let mut files = Vec::new();
292	
293	        let walker = WalkBuilder::new(&self.project_root)
294	            .standard_filters(true) // 自动 .gitignore 与常见忽略规则
295	            .hidden(false) // 不跳过隐藏文件（某些配置目录需要处理）
296	            .build();
297	
298	        for entry in walker {
299	            let entry = entry
300	                .map_err(|e| CodeConnectError::Index(format!("目录遍历失败: {}", e)))?;
301	
302	            // 只处理普通文件
303	            if !entry.file_type().map_or(false, |ft| ft.is_file()) {
304	                continue;
305	            }
306	
307	            let path = entry.path();
308	
309	            // 按扩展名过滤支持的编程语言
310	            if let Some(ext) = path.extension().and_then(|e| e.to_str()) {
311	                let supported = matches!(
312	                    ext,
313	                    "rs" | "ts" | "tsx" | "js" | "jsx" | "mjs" | "cjs" | "java" | "cs"
314	                );
315	                if supported {
316	                    files.push(path.to_path_buf());
317	                }
318	            }
319	        }
320	
321	        // 按路径排序以保证索引顺序稳定
322	        files.sort();
323	
324	        Ok(files)
325	    }
326	
327	    /// 将单个文件的解析结果写入存储
328	    ///
329	    /// 包括：文件元信息、符号定义、文件指纹、文件→符号映射，
330	    /// 以及将每个符号写入 tantivy 全文索引。
331	    fn write_parsed_file(&self, parsed: &ParsedFile) -> Result<(), CodeConnectError> {
332	        let file_path_str = &parsed.relative_path;
333	
334	        // ---- 写入文件元信息 ----
335	        let file_meta = FileMeta {
336	            file_path: file_path_str.clone(),
337	            language: parsed.language.to_string(),
338	            content_hash: parsed.content_hash.clone(),
339	            symbol_count: parsed.symbols.len() as u64,
340	            indexed_at: SystemTime::now()
341	                .duration_since(SystemTime::UNIX_EPOCH)
342	                .unwrap_or_default()
343	                .as_secs() as i64,
344	        };
345	
346	        let meta_bytes = serde_json::to_vec(&file_meta)
347	            .map_err(|e| CodeConnectError::Index(format!("序列化文件元信息失败: {}", e)))?;
348	        self.sled.put_file_meta(file_path_str, &meta_bytes)?;
349	
350	        // ---- 收集文件内所有符号 ID ----
351	        let mut file_symbol_ids: Vec<String> = Vec::with_capacity(parsed.symbols.len());
352	
353	        // ---- 写入每个符号定义 ----
354	        for symbol in &parsed.symbols {
355	            file_symbol_ids.push(symbol.id.clone());
356	
357	            let sym_bytes = serde_json::to_vec(symbol)
358	                .map_err(|e| CodeConnectError::Index(format!("序列化符号失败: {}", e)))?;
359	            self.sled.put_symbol(&symbol.id, &sym_bytes)?;
360	
361	            // ---- 写入 tantivy 全文索引 ----
362	            Self::add_symbol_to_tantivy(&self.tantivy, symbol, parsed, file_path_str)?;
363	        }
364	
365	        // ---- 写入文件→符号映射 ----
366	        let file_symbol_bytes = serde_json::to_vec(&file_symbol_ids)
367	            .map_err(|e| CodeConnectError::Index(format!("序列化文件符号映射失败: {}", e)))?;
368	        self.sled
369	            .put_file_symbols(file_path_str, &file_symbol_bytes)?;
370	
371	        // ---- 写入文件指纹 ----
372	        self.sled
373	            .put_fingerprint(file_path_str, parsed.content_hash.as_bytes())?;
374	
375	        Ok(())
376	    }
377	
378	    /// 将单个符号添加到 tantivy 全文索引
379	    fn add_symbol_to_tantivy(
380	        tantivy: &TantivyIndex,
381	        symbol: &codeconnect_core::types::Symbol,
382	        parsed: &ParsedFile,
383	        file_path_str: &str,
384	    ) -> Result<(), CodeConnectError> {
385	        // 将 SymbolKind 枚举映射为字符串
386	        let kind_str = match &symbol.kind {
387	            SymbolKind::Function => "function",
388	            SymbolKind::Method => "method",
389	            SymbolKind::Class => "class",
390	            SymbolKind::Interface => "interface",
391	            SymbolKind::Struct => "struct",
392	            SymbolKind::Enum => "enum",
393	            SymbolKind::Trait => "trait",
394	            SymbolKind::TypeAlias => "type_alias",
395	            SymbolKind::Variable => "variable",
396	            SymbolKind::Field => "field",
397	            SymbolKind::Module => "module",
398	            SymbolKind::Macro => "macro",
399	            SymbolKind::Parameter => "parameter",
400	            SymbolKind::Unknown(_) => "unknown",
401	        };
402	
403	        // 修饰符列表以逗号+空格拼接
404	        let modifiers_str = symbol.modifiers.join(", ");
405	
406	        tantivy.add_symbol(
407	            &symbol.id,
408	            &symbol.name,
409	            kind_str,
410	            parsed.language,
411	            file_path_str,
412	            symbol.signature.as_deref().unwrap_or(""),
413	            symbol.doc_comment.as_deref().unwrap_or(""),
414	            "", // definition — 暂不在解析器中提取
415	            "", // body_text — 暂不在解析器中提取
416	            symbol.parent_id.as_deref().unwrap_or(""),
417	            &modifiers_str,
418	            symbol.complexity.unwrap_or(0),
419	            "", // ast_hash — 暂不在此阶段计算
420	            symbol.is_exported,
421	        )
422	    }
423	}
424	
425	// ============================================================================
426	// 并行解析辅助函数
427	// ============================================================================
428	
429	/// 解析单个文件并提取所有结构化信息
430	///
431	/// 此函数设计为可在 rayon 并行迭代中调用，无外部可变依赖。
432	/// 所有数据通过返回值传递，由主线程统一写入存储。
433	fn parse_single_file(
434	    file_path: &Path,
435	    parser_registry: &Arc<ParserRegistry>,
436	    project_root: &Path,
437	) -> Result<ParsedFile, String> {
438	    // 查找对应的解析器
439	    let parser = parser_registry
440	        .get_for_file(file_path)
441	        .ok_or_else(|| format!("不支持的文件类型: {}", file_path.display()))?;
442	
443	    let language: &'static str = parser.language();
444	
445	    // 读取文件内容
446	    let source = std::fs::read_to_string(file_path)
447	        .map_err(|e| format!("读取文件失败 {}: {}", file_path.display(), e))?;
448	
449	    // 计算内容哈希（blake3::Hash 实现了 Display，输出十六进制字符串）
450	    let content_hash = blake3::hash(source.as_bytes()).to_string();
451	
452	    // 计算相对于项目根目录的路径
453	    let relative_path = file_path
454	        .strip_prefix(project_root)
455	        .unwrap_or(file_path)
456	        .to_string_lossy()
457	        .to_string();
458	
459	    // 解析源码为 AST
460	    let tree = parser
461	        .parse(&source)
462	        .map_err(|e| format!("解析失败 {}: {}", file_path.display(), e))?;
463	
464	    // 提取符号
465	    let symbols = parser.extract_symbols(&tree, &source, file_path);
466	
467	    // 提取调用
468	    let calls = parser.extract_calls(&tree, &source, file_path);
469	
470	    // 提取导入
471	    let imports = parser.extract_imports(&tree, &source, file_path);
472	
473	    let stats = FileIndexStats {
474	        symbols: symbols.len() as u64,
475	        calls: calls.len() as u64,
476	        imports: imports.len() as u64,
477	    };
478	
479	    Ok(ParsedFile {
480	        relative_path,
481	        content_hash,
482	        language,
483	        symbols,
484	        calls,
485	        imports,
486	        stats,
487	    })
488	}
489	
490	// ============================================================================
491	// 测试
492	// ============================================================================
493	
494	#[cfg(test)]
495	mod tests {
496	    use super::*;
497	
498	    /// 测试空项目（无源文件）不会出错
499	    #[test]
500	    fn test_collect_files_empty_dir() {
501	        let tmp = std::env::temp_dir().join("codeconnect_test_empty");
502	        let _ = std::fs::create_dir_all(&tmp);
503	
504	        // 这里只验证遍历逻辑不会在空目录崩溃
505	        // 注意：需要实际的索引实例，所以此处仅验证 collect_files 的逻辑模式
506	        assert!(tmp.exists());
507	
508	        let _ = std::fs::remove_dir_all(&tmp);
509	    }
510	
511	    /// 测试 FileIndexStats::merge 合并逻辑
512	    #[test]
513	    fn test_file_index_stats_merge() {
514	        let s1 = FileIndexStats {
515	            symbols: 10,
516	            calls: 5,
517	            imports: 2,
518	        };
519	        let s2 = FileIndexStats {
520	            symbols: 20,
521	            calls: 8,
522	            imports: 3,
523	        };
524	        let s3 = FileIndexStats::default();
525	
526	        let merged = FileIndexStats::merge(&[s1, s2, s3]);
527	        assert_eq!(merged.symbols, 30);
528	        assert_eq!(merged.calls, 13);
529	        assert_eq!(merged.imports, 5);
530	    }
531	}
