1	//! 解析器工厂
2	//!
3	//! 管理所有已注册的语言解析器，根据文件扩展名或语言名查找对应的解析器实例。
4	//! 使用 `Arc<dyn LanguageParser>` 实现零拷贝共享，避免每次查询都 clone 解析器。
5	
6	use std::collections::HashMap;
7	use std::path::Path;
8	use std::sync::Arc;
9	
10	use crate::r#trait::LanguageParser;
11	
12	/// 解析器注册表
13	///
14	/// 维护"扩展名 → 语言名"和"语言名 → 解析器"的双向映射，
15	/// 支持按文件路径自动检测语言。
16	pub struct ParserRegistry {
17	    /// 语言名 → 解析器实例
18	    parsers: HashMap<String, Arc<dyn LanguageParser>>,
19	    /// 文件扩展名 → 语言名
20	    ext_map: HashMap<String, String>,
21	}
22	
23	impl ParserRegistry {
24	    /// 创建空的解析器注册表
25	    pub fn new() -> Self {
26	        Self {
27	            parsers: HashMap::new(),
28	            ext_map: HashMap::new(),
29	        }
30	    }
31	
32	    /// 注册一个语言解析器
33	    ///
34	    /// 自动将解析器支持的所有文件扩展名映射到对应语言。
35	    pub fn register(&mut self, parser: Arc<dyn LanguageParser>) {
36	        let lang = parser.language().to_string();
37	        for ext in parser.file_extensions() {
38	            self.ext_map.insert(ext.to_string(), lang.clone());
39	        }
40	        self.parsers.insert(lang, parser);
41	    }
42	
43	    /// 根据文件路径推断语言并查找对应解析器
44	    ///
45	    /// 返回 `None` 表示不支持该文件类型。
46	    pub fn get_for_file(&self, file_path: &Path) -> Option<&Arc<dyn LanguageParser>> {
47	        let ext = file_path.extension()?.to_str()?;
48	        let ext_lower = ext.to_lowercase();
49	
50	        // TS/JS 特别处理 — 复合扩展名映射
51	        let lang_key = match ext_lower.as_str() {
52	            "ts" | "tsx" => "typescript",
53	            "js" | "jsx" | "mjs" | "cjs" => "javascript",
54	            "rs" => "rust",
55	            "java" => "java",
56	            "kt" | "kts" => "kotlin",
57	            "cs" => "csharp",
58	            other => other,
59	        };
60	
61	        self.parsers.get(lang_key)
62	    }
63	
64	    /// 根据语言名查找解析器
65	    pub fn get_for_language(&self, language: &str) -> Option<&Arc<dyn LanguageParser>> {
66	        self.parsers.get(language)
67	    }
68	
69	    /// 返回所有已注册的语言名
70	    pub fn registered_languages(&self) -> Vec<&str> {
71	        self.parsers.keys().map(|s| s.as_str()).collect()
72	    }
73	}
74	
75	impl Default for ParserRegistry {
76	    fn default() -> Self {
77	        Self::new()
78	    }
79	}
80

