1	//! Rust 语言解析器
2	//!
3	//! 使用 tree-sitter-rust grammar 解析 .rs 文件，
4	//! 提取函数、结构体、trait、枚举、方法等符号定义，
5	//! 以及函数调用和 use 导入语句。
6	
7	use std::path::Path;
8	use std::sync::Mutex;
9	
10	use codeconnect_core::error::CodeConnectError;
11	use codeconnect_core::symbol_id::StableSymbolId;
12	use codeconnect_core::types::{
13	    CallSite, CallType, Import, ImportResolution, SourceLocation, Symbol, SymbolKind,
14	};
15	use streaming_iterator::StreamingIterator;
16	use tree_sitter::{Parser, Query, QueryCursor, Tree};
17	
18	use crate::query_loader::load_rust_queries;
19	use crate::r#trait::LanguageParser;
20	
21	/// Rust 语言解析器
22	///
23	/// 包装了 tree-sitter-rust grammar 和一个 `Mutex<Parser>`，
24	/// 确保并发调用时的线程安全。缓存 Language 对象用于 Query 编译。
25	pub struct RustParser {
26	    /// tree-sitter 解析器实例（Mutex 因为 Parser 不是 Sync）
27	    parser: Mutex<Parser>,
28	    /// Rust language 对象（用于 Query::new 编译查询）
29	    language: tree_sitter::Language,
30	}
31	
32	impl RustParser {
33	    /// 创建新的 Rust 解析器
34	    pub fn new() -> Self {
35	        let mut parser = Parser::new();
36	        // tree-sitter-rust 0.23: LANGUAGE 是 LanguageFn 常量，通过 .into() 转为 Language
37	        let language: tree_sitter::Language = tree_sitter_rust::LANGUAGE.into();
38	        parser
39	            .set_language(&language)
40	            .expect("加载 Rust tree-sitter grammar 失败");
41	        Self {
42	            parser: Mutex::new(parser),
43	            language,
44	        }
45	    }
46	
47	    /// 将 tree-sitter 节点转为源码位置（0-based → 1-based）
48	    fn node_to_location(&self, node: tree_sitter::Node) -> SourceLocation {
49	        let start = node.start_position();
50	        let end = node.end_position();
51	        SourceLocation {
52	            file_path: String::new(), // 由外部调用者填充
53	            line: start.row as u64 + 1,
54	            column: start.column as u64 + 1,
55	            end_line: end.row as u64 + 1,
56	            end_column: end.column as u64 + 1,
57	        }
58	    }
59	
60	    /// 获取节点的源码文本（UTF-8 安全）
61	    fn node_text<'a>(&self, node: tree_sitter::Node, source: &'a str) -> &'a str {
62	        node.utf8_text(source.as_bytes()).unwrap_or("")
63	    }
64	}
65	
66	impl Default for RustParser {
67	    fn default() -> Self {
68	        Self::new()
69	    }
70	}
71	
72	impl LanguageParser for RustParser {
73	    fn language(&self) -> &'static str {
74	        "rust"
75	    }
76	
77	    fn file_extensions(&self) -> &[&str] {
78	        &["rs"]
79	    }
80	
81	    fn parse(&self, source: &str) -> Result<Tree, CodeConnectError> {
82	        let mut parser = self.parser.lock().map_err(|e| CodeConnectError::Parse {
83	            file: Path::new("").to_path_buf(),
84	            message: format!("获取解析器锁失败: {}", e),
85	        })?;
86	        parser
87	            .parse(source, None)
88	            .ok_or_else(|| CodeConnectError::Parse {
89	                file: Path::new("").to_path_buf(),
90	                message: "Rust 源码解析失败，可能包含语法错误".to_string(),
91	            })
92	    }
93	
94	    fn extract_symbols(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Symbol> {
95	        let queries = load_rust_queries();
96	        let file_path_str = file_path.to_string_lossy().to_string();
97	        let mut results = Vec::new();
98	
99	        let query = match Query::new(&self.language, &queries.symbols) {
100	            Ok(q) => q,
101	            Err(_) => return results,
102	        };
103	
104	        let mut cursor = QueryCursor::new();
105	        // tree-sitter 0.24: matches() 返回 StreamingIterator，不是标准 Iterator
106	        // 需要导入 streaming_iterator::StreamingIterator 使用 next()/advance()+get()
107	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
108	
109	        while let Some(m) = matches.next() {
110	            let mut name = String::new();
111	            let mut parent = String::new();
112	            let mut kind = SymbolKind::Unknown("unknown".to_string());
113	            let mut location = SourceLocation {
114	                file_path: file_path_str.clone(),
115	                line: 0,
116	                column: 0,
117	                end_line: 0,
118	                end_column: 0,
119	            };
120	
121	            for capture in m.captures {
122	                let node = capture.node;
123	                let capture_name = query.capture_names()[capture.index as usize];
124	
125	                match capture_name {
126	                    "symbol.name" => {
127	                        name = self.node_text(node, source).to_string();
128	                    }
129	                    "symbol.function" => {
130	                        kind = SymbolKind::Function;
131	                        location = self.node_to_location(node);
132	                    }
133	                    "symbol.method" => {
134	                        kind = SymbolKind::Method;
135	                        location = self.node_to_location(node);
136	                    }
137	                    "symbol.struct" => {
138	                        kind = SymbolKind::Struct;
139	                        location = self.node_to_location(node);
140	                    }
141	                    "symbol.trait" => {
142	                        kind = SymbolKind::Trait;
143	                        location = self.node_to_location(node);
144	                    }
145	                    "symbol.enum" => {
146	                        kind = SymbolKind::Enum;
147	                        location = self.node_to_location(node);
148	                    }
149	                    "symbol.type_alias" => {
150	                        kind = SymbolKind::TypeAlias;
151	                        location = self.node_to_location(node);
152	                    }
153	                    "symbol.macro" => {
154	                        kind = SymbolKind::Macro;
155	                        location = self.node_to_location(node);
156	                    }
157	                    "symbol.module" => {
158	                        kind = SymbolKind::Module;
159	                        location = self.node_to_location(node);
160	                    }
161	                    "symbol.variable" => {
162	                        kind = SymbolKind::Variable;
163	                        location = self.node_to_location(node);
164	                    }
165	                    "symbol.field" => {
166	                        kind = SymbolKind::Field;
167	                        location = self.node_to_location(node);
168	                    }
169	                    "symbol.parent" => {
170	                        parent = self.node_text(node, source).to_string();
171	                    }
172	                    _ => {}
173	                }
174	            }
175	
176	            if name.is_empty() {
177	                continue;
178	            }
179	
180	            let kind_str = match &kind {
181	                SymbolKind::Function => "function",
182	                SymbolKind::Method => "method",
183	                SymbolKind::Struct => "struct",
184	                SymbolKind::Trait => "trait",
185	                SymbolKind::Enum => "enum",
186	                SymbolKind::TypeAlias => "type_alias",
187	                SymbolKind::Macro => "macro",
188	                SymbolKind::Module => "module",
189	                SymbolKind::Variable => "variable",
190	                SymbolKind::Field => "field",
191	                _ => "unknown",
192	            };
193	
194	            let id = StableSymbolId::new("rust", &file_path_str, kind_str, &name);
195	
196	            // Rust 顶层符号默认是私有的，以大写字母开头的符号大概率是公开 API
197	            let is_exported = name.chars().next().map_or(false, |c| c.is_uppercase())
198	                || matches!(
199	                    kind,
200	                    SymbolKind::Function
201	                        | SymbolKind::Struct
202	                        | SymbolKind::Trait
203	                        | SymbolKind::Enum
204	                );
205	
206	            let parent_id = if parent.is_empty() {
207	                None
208	            } else {
209	                Some(StableSymbolId::new("rust", &file_path_str, "struct", &parent).to_string())
210	            };
211	
212	            let modifiers = if is_exported {
213	                vec!["pub".to_string()]
214	            } else {
215	                vec!["private".to_string()]
216	            };
217	
218	            results.push(Symbol {
219	                id: id.to_string(),
220	                name,
221	                kind,
222	                location,
223	                signature: None,
224	                doc_comment: None,
225	                parent_id,
226	                modifiers,
227	                is_exported,
228	                complexity: None,
229	            });
230	        }
231	
232	        results
233	    }
234	
235	    fn extract_calls(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<CallSite> {
236	        let queries = load_rust_queries();
237	        let file_path_str = file_path.to_string_lossy().to_string();
238	        let mut results = Vec::new();
239	
240	        let query = match Query::new(&self.language, &queries.calls) {
241	            Ok(q) => q,
242	            Err(_) => return results,
243	        };
244	
245	        let mut cursor = QueryCursor::new();
246	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
247	
248	        while let Some(m) = matches.next() {
249	            let mut callee_name = String::new();
250	            let mut call_type = CallType::Direct;
251	            let mut location = SourceLocation {
252	                file_path: file_path_str.clone(),
253	                line: 0,
254	                column: 0,
255	                end_line: 0,
256	                end_column: 0,
257	            };
258	
259	            for capture in m.captures {
260	                let node = capture.node;
261	                let capture_name = query.capture_names()[capture.index as usize];
262	
263	                match capture_name {
264	                    "call.name" => {
265	                        callee_name = self.node_text(node, source).to_string();
266	                    }
267	                    "call" => {
268	                        location = self.node_to_location(node);
269	                    }
270	                    "call.method" => {
271	                        call_type = CallType::Virtual; // Rust 方法调用可能通过 trait 动态分发
272	                        location = self.node_to_location(node);
273	                    }
274	                    "call.macro" => {
275	                        call_type = CallType::MacroExpansion;
276	                        location = self.node_to_location(node);
277	                    }
278	                    _ => {}
279	                }
280	            }
281	
282	            if !callee_name.is_empty() && location.line > 0 {
283	                results.push(CallSite {
284	                    caller_id: String::new(), // 由外部调用者上下文补充
285	                    callee_name,
286	                    location,
287	                    call_type,
288	                    confidence: 0.9,
289	                });
290	            }
291	        }
292	
293	        results
294	    }
295	
296	    fn extract_imports(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Import> {
297	        let queries = load_rust_queries();
298	        let file_path_str = file_path.to_string_lossy().to_string();
299	        let mut results = Vec::new();
300	
301	        let query = match Query::new(&self.language, &queries.imports) {
302	            Ok(q) => q,
303	            Err(_) => return results,
304	        };
305	
306	        let mut cursor = QueryCursor::new();
307	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
308	
309	        while let Some(m) = matches.next() {
310	            let mut import_path = String::new();
311	            let mut alias = None;
312	            let mut import_line: u64 = 0;
313	
314	            for capture in m.captures {
315	                let node = capture.node;
316	                let capture_name = query.capture_names()[capture.index as usize];
317	
318	                match capture_name {
319	                    "import.path" => {
320	                        import_path = self.node_text(node, source).to_string();
321	                    }
322	                    "import.name" => {
323	                        alias = Some(self.node_text(node, source).to_string());
324	                    }
325	                    "import" | "import.extern" => {
326	                        import_line = node.start_position().row as u64 + 1;
327	                    }
328	                    _ => {}
329	                }
330	            }
331	
332	            // 对于 extern crate（仅 alias 无 import_path），使用 alias 作为路径
333	            let path = if import_path.is_empty() {
334	                alias.clone().unwrap_or_default()
335	            } else {
336	                import_path
337	            };
338	
339	            if !path.is_empty() {
340	                results.push(Import {
341	                    file_path: file_path_str.clone(),
342	                    import_path: path,
343	                    alias,
344	                    line: import_line,
345	                    resolution: ImportResolution::Unresolved,
346	                });
347	            }
348	        }
349	
350	        results
351	    }
352	
353	    fn infer_package(&self, file_path: &Path, _source: &str) -> Option<String> {
354	        // Rust 项目：从文件路径的目录结构中推断 crate 名
355	        // 逐级向上查找父目录，跳过 "src" 目录，取第一个非空目录名
356	        let mut current = file_path.parent();
357	        while let Some(dir) = current {
358	            if let Some(name) = dir.file_name().and_then(|n| n.to_str()) {
359	                if name == "src" {
360	                    // 跳过 src 目录，继续向上查找
361	                    current = dir.parent();
362	                    continue;
363	                }
364	                if !name.is_empty() {
365	                    return Some(name.to_string());
366	                }
367	            }
368	            current = dir.parent();
369	        }
370	        None
371	    }
372	}
