//! Java 语言解析器
//!
//! 使用 tree-sitter-java grammar 解析 .java 文件，
//! 提取类、接口、方法、字段等符号定义，
//! 以及方法调用和 import 导入语句。

use std::path::Path;
use std::sync::Mutex;

use codeconnect_core::error::CodeConnectError;
use codeconnect_core::symbol_id::StableSymbolId;
use codeconnect_core::types::{
    CallSite, CallType, Import, ImportResolution, SourceLocation, Symbol, SymbolKind,
};
use streaming_iterator::StreamingIterator;
use tree_sitter::{Parser, Query, QueryCursor, Tree};

use crate::query_loader::load_java_queries;
use crate::r#trait::LanguageParser;

/// Java 语言解析器
///
/// 包装了 tree-sitter-java grammar 和一个 `Mutex<Parser>`，
/// 确保并发调用时的线程安全。
pub struct JavaParser {
    /// tree-sitter 解析器实例（Mutex 因为 Parser 不是 Sync）
    parser: Mutex<Parser>,
    /// Java language 对象（用于 Query::new 编译查询）
    language: tree_sitter::Language,
}

impl JavaParser {
    /// 创建新的 Java 解析器
    pub fn new() -> Self {
        let mut parser = Parser::new();
        let language: tree_sitter::Language = tree_sitter_java::LANGUAGE.into();
        parser
            .set_language(&language)
            .expect("加载 Java tree-sitter grammar 失败");
        Self {
            parser: Mutex::new(parser),
            language,
        }
    }

    /// 将 tree-sitter 节点转为源码位置（0-based → 1-based）
    fn node_to_location(&self, node: tree_sitter::Node, file_path: &str) -> SourceLocation {
        let start = node.start_position();
        let end = node.end_position();
        SourceLocation {
            file_path: file_path.to_string(),
            line: start.row as u64 + 1,
            column: start.column as u64 + 1,
            end_line: end.row as u64 + 1,
            end_column: end.column as u64 + 1,
        }
    }

    /// 获取节点的源码文本（UTF-8 安全）
    fn node_text<'a>(&self, node: tree_sitter::Node, source: &'a str) -> &'a str {
        node.utf8_text(source.as_bytes()).unwrap_or("")
    }
}

impl Default for JavaParser {
    fn default() -> Self {
        Self::new()
    }
}

impl LanguageParser for JavaParser {
    fn language(&self) -> &'static str {
        "java"
    }

    fn file_extensions(&self) -> &[&str] {
        &["java"]
    }

    fn parse(&self, source: &str) -> Result<Tree, CodeConnectError> {
        let mut parser = self.parser.lock().map_err(|e| CodeConnectError::Parse {
            file: Path::new("").to_path_buf(),
            message: format!("获取解析器锁失败: {}", e),
        })?;
        parser
            .parse(source, None)
            .ok_or_else(|| CodeConnectError::Parse {
                file: Path::new("").to_path_buf(),
                message: "Java 源码解析失败，可能包含语法错误".to_string(),
            })
    }

    fn extract_symbols(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Symbol> {
        let queries = load_java_queries();
        let file_path_str = file_path.to_string_lossy().to_string();
        let mut results = Vec::new();
        let mut seen_names: std::collections::HashSet<(String, String)> =
            std::collections::HashSet::new();

        let query = match Query::new(&self.language, &queries.symbols) {
            Ok(q) => q,
            Err(_) => return results,
        };

        let mut cursor = QueryCursor::new();
        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());

        while let Some(m) = matches.next() {
            let mut name = String::new();
            let mut kind = SymbolKind::Unknown("unknown".to_string());
            let mut location = self.node_to_location(tree.root_node(), &file_path_str);

            for capture in m.captures {
                let node = capture.node;
                let capture_name = query.capture_names()[capture.index as usize];

                match capture_name {
                    "symbol.name" => {
                        name = self.node_text(node, source).to_string();
                    }
                    "symbol.class" => {
                        kind = SymbolKind::Class;
                        location = self.node_to_location(node, &file_path_str);
                    }
                    "symbol.interface" => {
                        kind = SymbolKind::Interface;
                        location = self.node_to_location(node, &file_path_str);
                    }
                    "symbol.enum" => {
                        kind = SymbolKind::Enum;
                        location = self.node_to_location(node, &file_path_str);
                    }
                    "symbol.method" => {
                        kind = SymbolKind::Method;
                        location = self.node_to_location(node, &file_path_str);
                    }
                    "symbol.constructor" => {
                        kind = SymbolKind::Method;
                        location = self.node_to_location(node, &file_path_str);
                    }
                    "symbol.field" => {
                        kind = SymbolKind::Field;
                        location = self.node_to_location(node, &file_path_str);
                    }
                    "symbol.annotation" => {
                        kind = SymbolKind::Interface;
                        location = self.node_to_location(node, &file_path_str);
                    }
                    _ => {}
                }
            }

            if name.is_empty() {
                continue;
            }

            // 去重：同一文件中同名同类型的符号只保留一个
            let kind_str = kind_to_str(&kind);
            let dedup_key = (name.clone(), kind_str.to_string());
            if seen_names.contains(&dedup_key) {
                continue;
            }
            seen_names.insert(dedup_key);

            let id = StableSymbolId::new("java", &file_path_str, kind_str, &name);

            // Java 默认所有类和接口都是公开的
            let is_exported = matches!(kind, SymbolKind::Class | SymbolKind::Interface);

            let modifiers = if is_exported {
                vec!["public".to_string()]
            } else {
                vec![]
            };

            results.push(Symbol {
                id: id.to_string(),
                name,
                kind,
                location,
                signature: None,
                doc_comment: None,
                parent_id: None,
                modifiers,
                is_exported,
                complexity: None,
            });
        }

        results
    }

    fn extract_calls(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<CallSite> {
        let queries = load_java_queries();
        let file_path_str = file_path.to_string_lossy().to_string();
        let mut results = Vec::new();

        let query = match Query::new(&self.language, &queries.calls) {
            Ok(q) => q,
            Err(_) => return results,
        };

        let mut cursor = QueryCursor::new();
        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());

        while let Some(m) = matches.next() {
            let mut callee_name = String::new();
            let mut call_type = CallType::Direct;
            let mut location = SourceLocation {
                file_path: file_path_str.clone(),
                line: 0,
                column: 0,
                end_line: 0,
                end_column: 0,
            };

            for capture in m.captures {
                let node = capture.node;
                let capture_name = query.capture_names()[capture.index as usize];

                match capture_name {
                    "call.name" => {
                        callee_name = self.node_text(node, source).to_string();
                    }
                    "call" => {
                        location = self.node_to_location(node, &file_path_str);
                    }
                    "call.method" => {
                        call_type = CallType::Virtual;
                        location = self.node_to_location(node, &file_path_str);
                    }
                    "call.constructor" => {
                        call_type = CallType::Direct;
                        location = self.node_to_location(node, &file_path_str);
                    }
                    _ => {}
                }
            }

            if !callee_name.is_empty() && location.line > 0 {
                results.push(CallSite {
                    caller_id: String::new(),
                    callee_name,
                    location,
                    call_type,
                    confidence: 0.9,
                });
            }
        }

        results
    }

    fn extract_imports(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Import> {
        let queries = load_java_queries();
        let file_path_str = file_path.to_string_lossy().to_string();
        let mut results = Vec::new();

        let query = match Query::new(&self.language, &queries.imports) {
            Ok(q) => q,
            Err(_) => return results,
        };

        let mut cursor = QueryCursor::new();
        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());

        while let Some(m) = matches.next() {
            let mut import_path = String::new();
            let mut match_line: u64 = 0;

            for capture in m.captures {
                let node = capture.node;
                let capture_name = query.capture_names()[capture.index as usize];

                match capture_name {
                    "import.path" => {
                        import_path = self.node_text(node, source).to_string();
                    }
                    "import" => {
                        match_line = node.start_position().row as u64 + 1;
                    }
                    _ => {}
                }
            }

            if !import_path.is_empty() {
                results.push(Import {
                    file_path: file_path_str.clone(),
                    import_path,
                    alias: None,
                    line: match_line,
                    resolution: ImportResolution::Unresolved,
                });
            }
        }

        results
    }

    fn infer_package(&self, _file_path: &Path, _source: &str) -> Option<String> {
        // Java 项目：从源码中的 package 声明提取包名
        // 简化实现——返回文件父目录的倒数第二级
        // 完整实现应解析 package 声明
        let mut current = _file_path.parent();
        while let Some(dir) = current {
            if let Some(name) = dir.file_name().and_then(|n| n.to_str()) {
                if name == "src" || name == "main" || name == "java" {
                    current = dir.parent();
                    continue;
                }
                if !name.is_empty() {
                    return Some(name.to_string());
                }
            }
            current = dir.parent();
        }
        None
    }
}

/// 辅助函数：将 SymbolKind 转为字符串
fn kind_to_str(kind: &SymbolKind) -> &str {
    match kind {
        SymbolKind::Function => "function",
        SymbolKind::Method => "method",
        SymbolKind::Class => "class",
        SymbolKind::Interface => "interface",
        SymbolKind::Enum => "enum",
        SymbolKind::Field => "field",
        _ => "unknown",
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::path::PathBuf;

    fn parse_source(source: &str) -> (Tree, JavaParser) {
        let parser = JavaParser::new();
        let tree = parser.parse(source).expect("解析测试源码失败");
        (tree, parser)
    }

    #[test]
    fn test_parse_class() {
        let source = r#"
public class Hello {
    public void greet() {
        System.out.println("Hello");
    }
}
"#;
        let (tree, parser) = parse_source(source);
        let symbols = parser.extract_symbols(&tree, source, Path::new("Hello.java"));
        let cls = symbols.iter().find(|s| s.name == "Hello");
        assert!(cls.is_some(), "应找到 Hello 类");
        assert_eq!(cls.unwrap().kind, SymbolKind::Class);
    }

    #[test]
    fn test_parse_interface() {
        let source = r#"
public interface Service {
    void execute();
}
"#;
        let (tree, parser) = parse_source(source);
        let symbols = parser.extract_symbols(&tree, source, Path::new("Service.java"));
        let iface = symbols.iter().find(|s| s.name == "Service");
        assert!(iface.is_some(), "应找到 Service 接口");
        assert_eq!(iface.unwrap().kind, SymbolKind::Interface);
    }

    #[test]
    fn test_parse_method() {
        let source = r#"
public class Calculator {
    public int add(int a, int b) {
        return a + b;
    }
}
"#;
        let (tree, parser) = parse_source(source);
        let symbols = parser.extract_symbols(&tree, source, Path::new("Calculator.java"));
        let add_method = symbols.iter().find(|s| s.name == "add");
        assert!(add_method.is_some(), "应找到 add 方法");
        assert_eq!(add_method.unwrap().kind, SymbolKind::Method);
    }

    #[test]
    fn test_parse_enum() {
        let source = r#"
public enum Color {
    RED, GREEN, BLUE
}
"#;
        let (tree, parser) = parse_source(source);
        let symbols = parser.extract_symbols(&tree, source, Path::new("Color.java"));
        let enum_obj = symbols.iter().find(|s| s.name == "Color");
        assert!(enum_obj.is_some(), "应找到 Color 枚举");
        assert_eq!(enum_obj.unwrap().kind, SymbolKind::Enum);
    }

    #[test]
    fn test_parse_method_calls() {
        let source = r#"
public class Test {
    public void run() {
        foo();
        obj.bar();
        new Person("Alice");
    }
}
"#;
        let (tree, parser) = parse_source(source);
        let calls = parser.extract_calls(&tree, source, Path::new("Test.java"));
        let foo_call = calls.iter().find(|c| c.callee_name == "foo");
        let bar_call = calls.iter().find(|c| c.callee_name == "bar");
        let person_call = calls.iter().find(|c| c.callee_name == "Person");
        assert!(foo_call.is_some(), "应有 foo 调用");
        assert!(bar_call.is_some(), "应有 bar 方法调用");
        assert!(person_call.is_some(), "应有 Person 构造调用");
    }

    #[test]
    fn test_parse_imports() {
        let source = r#"
import java.util.List;
import java.util.Map;
public class Test {}
"#;
        let (tree, parser) = parse_source(source);
        let imports = parser.extract_imports(&tree, source, Path::new("Test.java"));
        assert!(!imports.is_empty(), "应有导入语句");
        let list_import = imports.iter().find(|i| i.import_path == "java.util.List");
        assert!(list_import.is_some(), "应有 java.util.List 导入");
    }

    #[test]
    fn test_language_name() {
        let parser = JavaParser::new();
        assert_eq!(parser.language(), "java");
    }

    #[test]
    fn test_file_extensions() {
        let parser = JavaParser::new();
        assert_eq!(parser.file_extensions(), &["java"]);
    }
}

//! 全量索引集成测试
//!
//! 测试完整流程：解析目录 → 构建符号 → 写入 tantivy + sled → 查询验证

#[cfg(test)]
mod tests {
    use std::path::PathBuf;
    use std::sync::Arc;

    use codeconnect_index::full_indexer::FullIndexer;
    use codeconnect_index::sled_store::SledStore;
    use codeconnect_index::tantivy_index::TantivyIndex;
    use codeconnect_parser::factory::ParserRegistry;
    use codeconnect_parser::rust::RustParser;
    use codeconnect_parser::typescript::TypeScriptParser;
    use codeconnect_parser::java::JavaParser;

    /// 获取项目根目录（从 crates/index/ 向上两级到 workspace 根）
    fn project_root() -> PathBuf {
        // 从 crate 的 CARGO_MANIFEST_DIR 推导 workspace 根目录
        let manifest_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
        // manifest_dir = F:\...\code-connect\crates\index
        manifest_dir
            .parent()
            .unwrap() // code-connect\crates
            .parent()
            .unwrap() // code-connect
            .to_path_buf()
    }

    /// 创建临时目录用于索引存储
    fn temp_index_dir(name: &str) -> (tempfile::TempDir, PathBuf, PathBuf) {
        let tmp = tempfile::tempdir().expect("创建临时目录失败");
        let tantivy_dir = tmp.path().join(format!("{}_tantivy", name));
        let sled_dir = tmp.path().join(format!("{}_sled", name));
        (tmp, tantivy_dir, sled_dir)
    }

    /// 创建注册了 Rust 解析器的注册表
    fn rust_registry() -> Arc<ParserRegistry> {
        let mut registry = ParserRegistry::new();
        registry.register(Arc::new(RustParser::new()));
        Arc::new(registry)
    }

    /// 创建注册了 TypeScript 解析器的注册表
    fn typescript_registry() -> Arc<ParserRegistry> {
        let mut registry = ParserRegistry::new();
        registry.register(Arc::new(TypeScriptParser::new()));
        Arc::new(registry)
    }

    /// 创建注册了 Java 解析器的注册表
    fn java_registry() -> Arc<ParserRegistry> {
        let mut registry = ParserRegistry::new();
        registry.register(Arc::new(JavaParser::new()));
        Arc::new(registry)
    }

    // ========================================================================
    // Rust 项目索引测试
    // ========================================================================

    #[test]
    fn test_index_rust_project() {
        let root = project_root();
        let fixture_dir = root.join("tests").join("fixtures").join("rust_sample");
        assert!(
            fixture_dir.exists(),
            "rust_sample fixture 目录应存在: {}",
            fixture_dir.display()
        );

        let (_tmp, tantivy_dir, sled_dir) = temp_index_dir("rust");
        let tantivy =
            TantivyIndex::open_or_create(&tantivy_dir).expect("创建 tantivy 索引失败");
        let sled = SledStore::open(&sled_dir).expect("创建 sled 存储失败");

        let registry = rust_registry();
        let mut indexer = FullIndexer::new(&fixture_dir, tantivy, sled, registry);

        let stats = indexer.run().expect("Rust 全量索引应成功");

        println!("Rust 索引统计: {:?}", stats);
        assert!(stats.files_scanned > 0, "应至少扫描到 1 个文件");
        assert!(stats.files_parsed > 0, "应至少成功解析 1 个文件");
        assert!(stats.symbols_found > 0, "应至少提取到 1 个符号");
        assert!(stats.failed_files.is_empty(), "不应有解析失败的文件");

        // 验证 tantivy 中有数据
        let doc_count = indexer.tantivy.doc_count().expect("查询文档数失败");
        assert!(doc_count > 0, "tantivy 索引中应有文档");

        // 验证搜索能返回结果
        let results = indexer
            .tantivy
            .search_by_name("User", 10)
            .expect("搜索 User 失败");
        assert!(!results.is_empty(), "搜索 User 应返回结果");

        let results = indexer
            .tantivy
            .search_by_name("authenticate", 10)
            .expect("搜索 authenticate 失败");
        assert!(!results.is_empty(), "搜索 authenticate 应返回结果");
    }

    #[test]
    fn test_index_rust_project_stats() {
        let root = project_root();
        let fixture_dir = root.join("tests").join("fixtures").join("rust_sample");

        let (_tmp, tantivy_dir, sled_dir) = temp_index_dir("rust_stats");
        let tantivy = TantivyIndex::open_or_create(&tantivy_dir).expect("创建索引失败");
        let sled = SledStore::open(&sled_dir).expect("创建存储失败");

        let registry = rust_registry();
        let mut indexer = FullIndexer::new(&fixture_dir, tantivy, sled, registry);

