1	//! Java 语言解析器
2	//!
3	//! 使用 tree-sitter-java grammar 解析 .java 文件，
4	//! 提取类、接口、枚举、方法、构造函数、字段、注解等符号定义，
5	//! 以及方法调用、对象创建和 import 导入语句。
6	
7	use std::path::Path;
8	use std::sync::Mutex;
9	
10	use codeconnect_core::error::CodeConnectError;
11	use codeconnect_core::symbol_id::StableSymbolId;
12	use codeconnect_core::types::{
13	    CallSite, CallType, Import, ImportResolution, SourceLocation, Symbol, SymbolKind,
14	};
15	use streaming_iterator::StreamingIterator;
16	use tree_sitter::{Parser, Query, QueryCursor, Tree};
17	
18	use crate::query_loader::load_java_queries;
19	use crate::r#trait::LanguageParser;
20	
21	/// Java 语言解析器
22	///
23	/// 包装了 tree-sitter-java grammar 和一个 `Mutex<Parser>`，
24	/// 确保并发调用时的线程安全。缓存 Language 对象用于 Query 编译。
25	pub struct JavaParser {
26	    /// tree-sitter 解析器实例（Mutex 因为 Parser 不是 Sync）
27	    parser: Mutex<Parser>,
28	    /// Java language 对象（用于 Query::new 编译查询）
29	    language: tree_sitter::Language,
30	}
31	
32	impl JavaParser {
33	    /// 创建新的 Java 解析器
34	    pub fn new() -> Self {
35	        let mut parser = Parser::new();
36	        let language: tree_sitter::Language = tree_sitter_java::LANGUAGE.into();
37	        parser
38	            .set_language(&language)
39	            .expect("加载 Java tree-sitter grammar 失败");
40	        Self {
41	            parser: Mutex::new(parser),
42	            language,
43	        }
44	    }
45	
46	    /// 将 tree-sitter 节点转为源码位置（0-based → 1-based）
47	    fn node_to_location(&self, node: tree_sitter::Node) -> SourceLocation {
48	        let start = node.start_position();
49	        let end = node.end_position();
50	        SourceLocation {
51	            file_path: String::new(), // 由外部调用者填充
52	            line: start.row as u64 + 1,
53	            column: start.column as u64 + 1,
54	            end_line: end.row as u64 + 1,
55	            end_column: end.column as u64 + 1,
56	        }
57	    }
58	
59	    /// 获取节点的源码文本（UTF-8 安全）
60	    fn node_text<'a>(&self, node: tree_sitter::Node, source: &'a str) -> &'a str {
61	        node.utf8_text(source.as_bytes()).unwrap_or("")
62	    }
63	}
64	
65	impl Default for JavaParser {
66	    fn default() -> Self {
67	        Self::new()
68	    }
69	}
70	
71	impl LanguageParser for JavaParser {
72	    fn language(&self) -> &'static str {
73	        "java"
74	    }
75	
76	    fn file_extensions(&self) -> &[&str] {
77	        &["java"]
78	    }
79	
80	    fn parse(&self, source: &str) -> Result<Tree, CodeConnectError> {
81	        let mut parser = self.parser.lock().map_err(|e| CodeConnectError::Parse {
82	            file: Path::new("").to_path_buf(),
83	            message: format!("获取解析器锁失败: {}", e),
84	        })?;
85	        parser
86	            .parse(source, None)
87	            .ok_or_else(|| CodeConnectError::Parse {
88	                file: Path::new("").to_path_buf(),
89	                message: "Java 源码解析失败，可能包含语法错误".to_string(),
90	            })
91	    }
92	
93	    fn extract_symbols(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Symbol> {
94	        let queries = load_java_queries();
95	        let file_path_str = file_path.to_string_lossy().to_string();
96	        let mut results = Vec::new();
97	
98	        let query = match Query::new(&self.language, &queries.symbols) {
99	            Ok(q) => q,
100	            Err(_) => return results,
101	        };
102	
103	        let mut cursor = QueryCursor::new();
104	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
105	
106	        while let Some(m) = matches.next() {
107	            let mut name = String::new();
108	            let mut kind = SymbolKind::Unknown("unknown".to_string());
109	            let mut location = SourceLocation {
110	                file_path: file_path_str.clone(),
111	                line: 0,
112	                column: 0,
113	                end_line: 0,
114	                end_column: 0,
115	            };
116	
117	            for capture in m.captures {
118	                let node = capture.node;
119	                let capture_name = query.capture_names()[capture.index as usize];
120	
121	                match capture_name {
122	                    "symbol.name" => {
123	                        name = self.node_text(node, source).to_string();
124	                    }
125	                    "symbol.class" => {
126	                        kind = SymbolKind::Class;
127	                        location = self.node_to_location(node);
128	                    }
129	                    "symbol.interface" => {
130	                        kind = SymbolKind::Interface;
131	                        location = self.node_to_location(node);
132	                    }
133	                    "symbol.enum" => {
134	                        kind = SymbolKind::Enum;
135	                        location = self.node_to_location(node);
136	                    }
137	                    "symbol.method" => {
138	                        kind = SymbolKind::Method;
139	                        location = self.node_to_location(node);
140	                    }
141	                    "symbol.constructor" => {
142	                        kind = SymbolKind::Method; // 构造函数归类为 Method，通过 name 区分
143	                        location = self.node_to_location(node);
144	                    }
145	                    "symbol.field" => {
146	                        kind = SymbolKind::Field;
147	                        location = self.node_to_location(node);
148	                    }
149	                    "symbol.annotation" => {
150	                        kind = SymbolKind::Interface; // 注解本质是特殊的接口
151	                        location = self.node_to_location(node);
152	                    }
153	                    _ => {}
154	                }
155	            }
156	
157	            if name.is_empty() {
158	                continue;
159	            }
160	
161	            let kind_str = match &kind {
162	                SymbolKind::Class => "class",
163	                SymbolKind::Interface => "interface",
164	                SymbolKind::Enum => "enum",
165	                SymbolKind::Method => "method",
166	                SymbolKind::Field => "field",
167	                _ => "unknown",
168	            };
169	
170	            let id = StableSymbolId::new("java", &file_path_str, kind_str, &name);
171	
172	            // Java 类、接口、枚举和方法默认通过 public 修饰符控制可见性
173	            // 此处简化处理：标记为导出，实际可见性由 scope 查询另行确定
174	            let is_exported = matches!(
175	                kind,
176	                SymbolKind::Class | SymbolKind::Interface | SymbolKind::Enum
177	            );
178	
179	            let modifiers = if is_exported {
180	                vec!["public".to_string()]
181	            } else {
182	                vec!["default".to_string()]
183	            };
184	
185	            results.push(Symbol {
186	                id: id.to_string(),
187	                name,
188	                kind,
189	                location,
190	                signature: None,
191	                doc_comment: None,
192	                parent_id: None,
193	                modifiers,
194	                is_exported,
195	                complexity: None,
196	            });
197	        }
198	
199	        results
200	    }
201	
202	    fn extract_calls(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<CallSite> {
203	        let queries = load_java_queries();
204	        let file_path_str = file_path.to_string_lossy().to_string();
205	        let mut results = Vec::new();
206	
207	        let query = match Query::new(&self.language, &queries.calls) {
208	            Ok(q) => q,
209	            Err(_) => return results,
210	        };
211	
212	        let mut cursor = QueryCursor::new();
213	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
214	
215	        while let Some(m) = matches.next() {
216	            let mut callee_name = String::new();
217	            let mut call_type = CallType::Direct;
218	            let mut location = SourceLocation {
219	                file_path: file_path_str.clone(),
220	                line: 0,
221	                column: 0,
222	                end_line: 0,
223	                end_column: 0,
224	            };
225	
226	            for capture in m.captures {
227	                let node = capture.node;
228	                let capture_name = query.capture_names()[capture.index as usize];
229	
230	                match capture_name {
231	                    "call.name" => {
232	                        callee_name = self.node_text(node, source).to_string();
233	                    }
234	                    "call" => {
235	                        location = self.node_to_location(node);
236	                    }
237	                    "call.method" => {
238	                        call_type = CallType::Virtual; // Java 对象方法调用可能通过动态分发
239	                        location = self.node_to_location(node);
240	                    }
241	                    "call.constructor" => {
242	                        call_type = CallType::Direct;
243	                        location = self.node_to_location(node);
244	                    }
245	                    _ => {}
246	                }
247	            }
248	
249	            if !callee_name.is_empty() && location.line > 0 {
250	                results.push(CallSite {
251	                    caller_id: String::new(), // 由外部调用者上下文补充
252	                    callee_name,
253	                    location,
254	                    call_type,
255	                    confidence: 0.9,
256	                });
257	            }
258	        }
259	
260	        results
261	    }
262	
263	    fn extract_imports(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Import> {
264	        let queries = load_java_queries();
265	        let file_path_str = file_path.to_string_lossy().to_string();
266	        let mut results = Vec::new();
267	
268	        let query = match Query::new(&self.language, &queries.imports) {
269	            Ok(q) => q,
270	            Err(_) => return results,
271	        };
272	
273	        let mut cursor = QueryCursor::new();
274	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
275	
276	        // 遍历所有匹配：import 路径与 package 声明
277	        while let Some(m) = matches.next() {
278	            let mut import_path = String::new();
279	            let mut import_line: u64 = 0;
280	
281	            for capture in m.captures {
282	                let node = capture.node;
283	                let capture_name = query.capture_names()[capture.index as usize];
284	
285	                match capture_name {
286	                    "import.path" => {
287	                        import_path = self.node_text(node, source).to_string();
288	                    }
289	                    "import" => {
290	                        import_line = node.start_position().row as u64 + 1;
291	                    }
292	                    "import.package" => {
293	                        import_path = self.node_text(node, source).to_string();
294	                        import_line = node.start_position().row as u64 + 1;
295	                    }
296	                    _ => {}
297	                }
298	            }
299	
300	            if !import_path.is_empty() {
301	                // 检查是否已存在相同路径的记录（避免重复）
302	                if !results.iter().any(|i: &Import| i.import_path == import_path) {
303	                    results.push(Import {
304	                        file_path: file_path_str.clone(),
305	                        import_path,
306	                        alias: None,
307	                        line: import_line,
308	                        resolution: ImportResolution::Unresolved,
309	                    });
310	                }
311	            }
312	        }
313	
314	        results
315	    }
316	
317	    fn infer_package(&self, file_path: &Path, _source: &str) -> Option<String> {
318	        // Java 项目：从目录结构推断包名
319	        // 逐级向上查找父目录，直到遇到非 Java 包名的目录
320	        // 典型结构：src/main/java/com/example/MyClass.java → com.example
321	        let mut components: Vec<&str> = Vec::new();
322	
323	        // 收集文件名上方的所有目录名，直到遇到特殊目录（src, java, test 等）
324	        let mut current = file_path.parent();
325	        let stop_dirs = ["src", "java", "test", "main", "resources"];
326	
327	        while let Some(dir) = current {
328	            if let Some(name) = dir.file_name().and_then(|n| n.to_str()) {
329	                let lower = name.to_lowercase();
330	                if stop_dirs.contains(&lower.as_str()) {
331	                    break;
332	                }
333	                if !name.is_empty() && !name.starts_with('.') {
334	                    components.push(name);
335	                }
336	            }
337	            current = dir.parent();
338	        }
339	
340	        if components.is_empty() {
341	            None
342	        } else {
343	            components.reverse();
344	            Some(components.join("."))
345	        }
346	    }
347	}
348	
349	#[cfg(test)]
350	mod tests {
351	    use super::*;
352	    use std::path::PathBuf;
353	
354	    /// 辅助函数：创建解析器并返回解析结果
355	    fn parse_source(source: &str) -> (Tree, JavaParser) {
356	        let parser = JavaParser::new();
357	        let tree = parser.parse(source).expect("解析测试源码失败");
358	        (tree, parser)
359	    }
360	
361	    #[test]
362	    fn test_parse_simple_class() {
363	        let source = r#"
364	public class HelloWorld {
365	    public static void main(String[] args) {
366	        System.out.println("Hello, World!");
367	    }
368	}
369	"#;
370	        let (tree, parser) = parse_source(source);
371	        let symbols = parser.extract_symbols(&tree, source, Path::new("test.java"));
372	        let class_sym = symbols.iter().find(|s| s.name == "HelloWorld");
373	        assert!(class_sym.is_some(), "应找到 HelloWorld 类");
374	        assert_eq!(class_sym.unwrap().kind, SymbolKind::Class);
375	    }
376	
377	    #[test]
378	    fn test_parse_interface() {
379	        let source = r#"
380	public interface Printable {
381	    void print();
382	}
383	"#;
384	        let (tree, parser) = parse_source(source);
385	        let symbols = parser.extract_symbols(&tree, source, Path::new("test.java"));
386	        let interface_sym = symbols.iter().find(|s| s.name == "Printable");
387	        assert!(interface_sym.is_some(), "应找到 Printable 接口");
388	        assert_eq!(interface_sym.unwrap().kind, SymbolKind::Interface);
389	    }
390	
391	    #[test]
392	    fn test_parse_enum() {
393	        let source = r#"
394	public enum Color {
395	    RED, GREEN, BLUE;
396	}
397	"#;
398	        let (tree, parser) = parse_source(source);
399	        let symbols = parser.extract_symbols(&tree, source, Path::new("test.java"));
400	        let enum_sym = symbols.iter().find(|s| s.name == "Color");
401	        assert!(enum_sym.is_some(), "应找到 Color 枚举");
402	        assert_eq!(enum_sym.unwrap().kind, SymbolKind::Enum);
403	    }
404	
405	    #[test]
406	    fn test_parse_method() {
407	        let source = r#"
408	public class Calculator {
409	    public int add(int a, int b) {
410	        return a + b;
411	    }
412	}
