        let stats = indexer.run().expect("索引应成功");

        // 验证基本统计约束
        assert!(stats.symbols_found > 0, "应有符号");
        assert!(
            stats.files_parsed <= stats.files_scanned,
            "解析文件数不应超过扫描文件数"
        );
    }

    // ========================================================================
