    /// 诊断测试：打印 Java 测试源码的 AST 节点类型，帮助调试 scm query 匹配问题
    #[test]
    fn test_dump_java_ast_nodes() {
        let source = "public class Hello { public void greet() {} }";
        let parser = JavaParser::new();
        let tree = parser.parse(source).expect("解析失败");
        let mut node_types: Vec<String> = Vec::new();
        let mut cursor = tree.root_node().walk();
        fn collect_nodes(
            cursor: &mut tree_sitter::TreeCursor,
            node_types: &mut Vec<String>,
            depth: usize,
        ) {
            let node = cursor.node();
            let indent = "  ".repeat(depth);
            node_types.push(format!("{}{} ({})", indent, node.kind(), node.child_count()));
            if cursor.goto_first_child() {
                collect_nodes(cursor, node_types, depth + 1);
                cursor.goto_parent();
            }
            if cursor.goto_next_sibling() {
                collect_nodes(cursor, node_types, depth + 1);
                cursor.goto_parent();
            }
        }
        collect_nodes(&mut cursor, &mut node_types, 0);

        // 输出 AST 结构，便于调试
        for t in &node_types {
            println!("{}", t);
        }

        // 验证基础节点存在
        let all_types = node_types.join("\n");
        let expected_nodes = ["class_declaration", "method_declaration"];
        for exp in &expected_nodes {
            assert!(
                all_types.contains(exp),
                "AST 应包含节点类型 '{}'，但实际未找到。\n所有节点类型:\n{}",
                exp,
                all_types
            );
        }
    }
}

