/// 诊断测试：打印 Java 构造器 + 方法调用 AST 结构
#[test]
fn test_dump_constructor_and_calls_ast() {
    let source = r#"public class Point { public Point(int x) { } public void run() { new Thread().start(); foo(); } }"#;
    let parser = JavaParser::new();
    let tree = parser.parse(source).expect("解析失败");
    let mut node_types: Vec<String> = Vec::new();
    let mut cursor = tree.root_node().walk();
    fn collect_nodes(
        cursor: &mut tree_sitter::TreeCursor,
        node_types: &mut Vec<String>,
        depth: usize,
    ) {
        let node = cursor.node();
        let indent = "  ".repeat(depth);
        let kind = node.kind();
        let start = node.start_position();
        node_types.push(format!(
            "{}├─ {} ({}) [L{}]",
            indent,
            kind,
            node.child_count(),
            start.row + 1,
        ));
        if cursor.goto_first_child() {
            collect_nodes(cursor, node_types, depth + 1);
            cursor.goto_parent();
        }
        if cursor.goto_next_sibling() {
            collect_nodes(cursor, node_types, depth + 1);
            cursor.goto_parent();
        }
    }
    collect_nodes(&mut cursor, &mut node_types, 0);

    for t in &node_types {
        println!("{}", t);
    }

    let all_types = node_types.join("\n");
    assert!(all_types.contains("constructor_declaration"), "应包含 constructor_declaration");
    assert!(all_types.contains("object_creation_expression"), "应包含 object_creation_expression");
}

