/// 诊断测试：检查 tree-sitter-java 是否解析 new 表达式
#[test]
fn test_dump_constructor_and_calls_ast() {
    // 使用完整的 main 方法语法测试
    let source = r#"public class Main { public static void main(String[] args) { new Thread(); } }"#;
    let parser = JavaParser::new();
    let tree = parser.parse(source).expect("解析失败");

    // 遍历整棵树，查找包含 "Thread" 的节点
    let root = tree.root_node();
    println!("root kind: {}, has_error: {}", root.kind(), root.has_error());
    println!("root text: {}", source);

    // 检查是否有解析错误
    fn check_errors(node: tree_sitter::Node, source: &str) -> Vec<String> {
        let mut errors = Vec::new();
        if node.is_error() || node.is_missing() {
            errors.push(format!("ERROR node: kind={}, text={:?}",
                node.kind(),
                node.utf8_text(source.as_bytes()).unwrap_or("?")));
        }
        for child in node.children(&mut node.walk()) {
            errors.extend(check_errors(child, source));
        }
        errors
    }
    let errors = check_errors(root, source);
    for e in &errors {
        println!("{}", e);
    }

    // 找到所有节点类型
    let mut all_kinds: Vec<String> = Vec::new();
    fn collect_kinds(node: tree_sitter::Node, all: &mut Vec<String>) {
        all.push(node.kind().to_string());
        for child in node.children(&mut node.walk()) {
            collect_kinds(child, all);
        }
    }
    collect_kinds(root, &mut all_kinds);
    let unique: std::collections::HashSet<String> = all_kinds.iter().cloned().collect();
    let mut sorted: Vec<_> = unique.iter().collect();
    sorted.sort();
    println!("All node kinds: {:?}", sorted);

    assert!(!root.has_error(), "不应有解析错误。errors: {:?}", errors);
}

